process.scriptContent:
$ErrorActionPreference = 'Stop'
$data = $env:KLEVADEPLOY_DATA_DIR
if ([string]::IsNullOrWhiteSpace($data)) { throw 'KLEVADEPLOY_DATA_DIR mancante' }
$temp = $env:KLEVADEPLOY_TEMP_DIR
if ([string]::IsNullOrWhiteSpace($temp)) { $temp = Join-Path $data 'temp' }
$media = Join-Path $temp 'KlevaDeploy\sql2022_media'
New-Item -ItemType Directory -Force -Path $media | Out-Null
$bootstrapper = Join-Path $data 'installers\sql-express-2022-sqlpass\SQL2022-SSEI-Expr.exe'
if (!(Test-Path $bootstrapper)) { throw ('Bootstrapper non trovato: ' + $bootstrapper) }
& $bootstrapper /Q /ACTION=Download /MEDIAPATH="$media" /MEDIATYPE=Core /LANGUAGE=ENU /QUIET
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
exit 0
